from pathlib import Pathimport pytestfrom app.modules.editor.ffmpeg import (    concat,    export,    extract,    make_test_clip,    probe_duration,    xfade,)from app.modules.editor.service import EditorServicefrom app.modules.jobs.domain import TransitionTypeDURATION_TOLERANCE = 0.35@pytest.fixturedef sample_clip(tmp_path: Path) -> Path:    clip_path = tmp_path / "sample.mp4"    make_test_clip(clip_path, duration=3.0)    assert clip_path.exists()    return clip_pathdef test_make_test_clip_duration(sample_clip: Path) -> None:    duration = probe_duration(sample_clip)    assert duration == pytest.approx(3.0, abs=DURATION_TOLERANCE)def test_extract_duration(sample_clip: Path, tmp_path: Path) -> None:    output_path = tmp_path / "extracted.mp4"    extract(sample_clip, output_path, start=0.5, end=2.0)    assert output_path.exists()    assert probe_duration(output_path) == pytest.approx(1.5, abs=DURATION_TOLERANCE)def test_concat_duration(sample_clip: Path, tmp_path: Path) -> None:    clip_a = tmp_path / "clip_a.mp4"    clip_b = tmp_path / "clip_b.mp4"    output_path = tmp_path / "merged_cut.mp4"    extract(sample_clip, clip_a, start=0.0, end=1.0)    extract(sample_clip, clip_b, start=1.0, end=2.0)    concat([clip_a, clip_b], output_path)    assert output_path.exists()    assert probe_duration(output_path) == pytest.approx(2.0, abs=DURATION_TOLERANCE)def test_xfade_fade_duration(sample_clip: Path, tmp_path: Path) -> None:    clip_a = tmp_path / "fade_a.mp4"    clip_b = tmp_path / "fade_b.mp4"    output_path = tmp_path / "merged_fade.mp4"    transition_duration = 0.5    extract(sample_clip, clip_a, start=0.0, end=1.5)    extract(sample_clip, clip_b, start=1.5, end=3.0)    xfade(        [clip_a, clip_b],        output_path,        TransitionType.FADE,        transition_duration,    )    assert output_path.exists()    expected_duration = 1.5 + 1.5 - transition_duration    assert probe_duration(output_path) == pytest.approx(        expected_duration,        abs=DURATION_TOLERANCE,    )def test_xfade_slide_duration(sample_clip: Path, tmp_path: Path) -> None:    clip_a = tmp_path / "slide_a.mp4"    clip_b = tmp_path / "slide_b.mp4"    output_path = tmp_path / "merged_slide.mp4"    transition_duration = 0.5    extract(sample_clip, clip_a, start=0.0, end=1.5)    extract(sample_clip, clip_b, start=1.5, end=3.0)    xfade(        [clip_a, clip_b],        output_path,        TransitionType.SLIDE,        transition_duration,    )    assert output_path.exists()    expected_duration = 1.5 + 1.5 - transition_duration    assert probe_duration(output_path) == pytest.approx(        expected_duration,        abs=DURATION_TOLERANCE,    )def test_export_duration(sample_clip: Path, tmp_path: Path) -> None:    output_path = tmp_path / "exported.mp4"    export(sample_clip, output_path)    assert output_path.exists()    assert probe_duration(output_path) == pytest.approx(3.0, abs=DURATION_TOLERANCE)def test_editor_service_merge_cut(sample_clip: Path, tmp_path: Path) -> None:    service = EditorService()    clip_a = tmp_path / "svc_a.mp4"    clip_b = tmp_path / "svc_b.mp4"    output_path = tmp_path / "svc_cut.mp4"    service.extract(sample_clip, clip_a, start=0.0, end=1.0)    service.extract(sample_clip, clip_b, start=1.0, end=2.0)    service.merge_clips(        [clip_a, clip_b],        output_path,        TransitionType.CUT,        0.0,    )    assert output_path.exists()    assert probe_duration(output_path) == pytest.approx(2.0, abs=DURATION_TOLERANCE)